export default function Skills() {
  const [activeToolId, setActiveToolId] = useState("figma");

  const scrollRef = useRef<HTMLDivElement>(null);
  const [isHovered, setIsHovered] = useState(false);
  const [isDragging, setIsDragging] = useState(false);
  const [startX, setStartX] = useState(0);
  const [scrollLeftPos, setScrollLeftPos] = useState(0);

  // Auto-scroll logic
  useEffect(() => {
    let animationFrameId: number;
    let lastTime = performance.now();

    const scroll = (time: number) => {
      const deltaTime = time - lastTime;
      if (scrollRef.current && !isHovered && !isDragging && deltaTime > 16) {
        if (scrollRef.current.scrollLeft <= 0) {
          scrollRef.current.scrollLeft = scrollRef.current.scrollWidth / 2;
        }
        scrollRef.current.scrollLeft -= 1;
        lastTime = time;
      }
      animationFrameId = requestAnimationFrame(scroll);
    };

    animationFrameId = requestAnimationFrame(scroll);
    return () => cancelAnimationFrame(animationFrameId);
  }, [isHovered, isDragging]);

  const handleMouseDown = useCallback((e: React.MouseEvent) => {
    setIsDragging(true);
    if (!scrollRef.current) return;
    setStartX(e.pageX - scrollRef.current.offsetLeft);
    setScrollLeftPos(scrollRef.current.scrollLeft);
  }, []);

  const handleMouseMove = useCallback(
    (e: React.MouseEvent) => {
      if (!isDragging || !scrollRef.current) return;
      e.preventDefault();
      const x = e.pageX - scrollRef.current.offsetLeft;
      const walk = (x - startX) * 2;
      scrollRef.current.scrollLeft = scrollLeftPos - walk;
    },
    [isDragging, startX, scrollLeftPos],
  );

  const handleMouseUpOrLeave = useCallback(() => {
    setIsDragging(false);
  }, []);

  const activeTool =
    toolsData.find(
      (t) =>
        t.id.toLowerCase() === activeToolId?.toLowerCase() ||
        t.id === activeToolId,
    ) || toolsData[0];

  return (
    <section className="relative w-full py-20 bg-transparent font-sans text-[#111] overflow-hidden">
      {/* Header */}
      <div className="max-w-7xl mx-auto px-6 md:px-12 flex flex-col md:flex-row justify-between items-start gap-8 mb-5">
        <motion.div 
          initial={{ opacity: 0, y: 50, rotateX: -20, perspective: 1000 }}
          whileInView={{ opacity: 1, y: 0, rotateX: 0 }}
          transition={{ duration: 0.8, ease: "easeOut" }}
          viewport={{ once: true, amount: 0.3 }}
          className="w-full md:w-3/5"
        >
          <h2 className="text-[2.5rem] md:text-5xl lg:text-6xl font-semibold tracking-tight leading-[1.1]">
            My Technical <br />
            <span className="font-bold text-[#ea5b25]">
              Background Skills
            </span>
            <br />
            {/* <span className="font-bold text-[#ea5b25]">Accomplishments</span> */}
          </h2>
        </motion.div>
        {/* <div className="w-full md:w-2/5 flex items-center pt-2 md:pt-4">
          <p className="text-[#555] text-sm md:text-base leading-relaxed">
            Now that you’ve known a bit about me, let me walk you through what I bring to the table where my capabilities turn ideas into reality.
Here’s a quick dive into the section that highlights the tools and strengths behind my work.
          </p>
        </div> */}
      </div>

      {/* Marquee logos */}
      <div
        ref={scrollRef as any}
        className="relative h-[300px] flex items-center justify-start w-full mb-16 md:mb-10 overflow-x-auto overflow-y-hidden cursor-grab active:cursor-grabbing select-none [mask-image:_linear-gradient(to_right,transparent_0,_black_328px,_black_calc(100%-328px),transparent_100%)] [&::-webkit-scrollbar]:hidden [-ms-overflow-style:'none'] [scrollbar-width:'none']"
        // onMouseEnter={() => setIsHovered(true)}
        onMouseLeave={() => {
          setIsHovered(false);
          handleMouseUpOrLeave();
        }}
        onTouchStart={() => setIsHovered(true)}
        onTouchEnd={() => setIsHovered(false)}
        onMouseDown={handleMouseDown}
        onMouseMove={handleMouseMove}
        onMouseUp={handleMouseUpOrLeave}
      >
        <div className="flex w-max relative gap-6 md:gap-10 py-4">
          {/* Duplicate list multiple times for seamless infinite scroll */}
          {[
            ...toolsData,
            ...toolsData,
            ...toolsData,
            ...toolsData,
            ...toolsData,
            ...toolsData,
          ].map((tool, idx) => {
            const isActive = activeToolId === tool.id;
            return (
              <div
                key={idx}
                onClick={() => setActiveToolId(tool.id)}
                className={`w-[120px] h-[160px] md:w-[150px] md:h-[200px] rounded-full border-[1.5px] flex items-center justify-center cursor-pointer transition-all duration-300 transform flex-shrink-0 ${
                  isActive
                    ? "border-[#ea5b25] shadow-lg bg-orange-50/30 scale-105"
                    : "border-gray-200 bg-white hover:border-[#ea5b25] hover:scale-105 shadow-sm"
                }`}
              >
                <div
                  className={`transition-transform duration-300 ${isActive ? "scale-110" : "scale-100 opacity-100"}`}
                >
                  {tool.logo}
                </div>
              </div>
            );
          })}
        </div>
      </div>

      {/* Progress Bars Region */}
      <motion.div 
        initial={{ opacity: 0, y: 40, scale: 0.95 }}
        whileInView={{ opacity: 1, y: 0, scale: 1 }}
        transition={{ duration: 0.7, ease: "easeOut", delay: 0.2 }}
        viewport={{ once: true, amount: 0.3 }}
        className="max-w-7xl mx-auto px-6 md:px-12 grid grid-cols-1 md:grid-cols-2 gap-12 md:gap-20 transition-opacity duration-500"
      >
        {/* Left Column Stats */}
        <div className="flex flex-col justify-center md:pb-[50px]">
          <h3 className="text-3xl md:text-4xl font-bold tracking-tight text-[#ea5b25] mb-6">
            {activeTool.stats.left.heading}
          </h3>
          <p className="text-[#555] text-base md:text-lg leading-relaxed">
            {activeTool.stats.left.description}
          </p>
        </div>

        {/* Right Column Stats */}
        <div className="flex flex-col gap-6 md:gap-8 justify-center">
          <div className="w-full">
            <div className="flex justify-between items-end mb-3">
              <span className="font-semibold text-lg">Proficiency</span>
              <span className="font-bold text-lg">
                {activeTool.stats.right.proficiency}%
              </span>
            </div>
            <div className="w-full bg-gray-100 h-1.5 rounded-full relative mb-1">
              <div
                className="bg-[#ea5b25] h-1.5 rounded-full relative transition-all duration-1000 ease-out"
                style={{ width: `${activeTool.stats.right.proficiency}%` }}
              >
                <div className="absolute right-0 top-1/2 -translate-y-1/2 translate-x-1/2 w-4 h-4 bg-white border-[2.5px] border-[#ea5b25] rounded-full shadow-sm z-10"></div>
              </div>
            </div>
          </div>

          <div className="flex flex-col gap-4">
            <h4 className="font-bold text-lg text-[#111]">Projects Used In:</h4>
            <ul className="space-y-4">
              {activeTool.stats.right.projects.map((project, i) => (
                <motion.li
                  key={i}
                  initial={{ opacity: 0, x: 20 }}
                  whileInView={{ opacity: 1, x: 0 }}
                  transition={{ duration: 0.5, delay: 0.4 + i * 0.1 }}
                  viewport={{ once: true }}
                  className="flex items-center gap-3 text-[#555] font-medium text-base"
                >
                  <span className="w-2.5 h-2.5 rounded-full bg-[#ea5b25] flex-shrink-0"></span>
                  {project}
                </motion.li>
              ))}
            </ul>
          </div>
        </div>
      </motion.div>

      {/* JS-based infinite scroll implemented without CSS keyframes */}
    </section>
  );
}
